mapper.select:
SELECT f.* FROM wx_friend_info f INNER JOIN ( SELECT MAX(ff.id) AS id FROM wx_friend_info ff
ff.is_del = 0 AND ff.is_external = 1
AND ff.corp_id IN
#{corpId}
AND ff.owner_user_id IN
#{userId}
GROUP BY ff.user_id ) dedup ON dedup.id = f.id ORDER BY f.create_time DESC LIMIT #{offset}, #{limit}
